query:
UPDATE pro_rata_encerradas 
SET vlrPerdido = CAST(comissao AS DECIMAL(10,4)) * GREATEST(0, qtdParcelasTotal - qtdParcelasPagas)
WHERE comissao IS NOT NULL AND qtdParcelasTotal IS NOT NULL AND qtdParcelasPagas IS NOT NULL;

